const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      formattedData: "No data found.",
      totalItems: 0,
      highCount: 0,
      mediumCount: 0,
      lowCount: 0
    }
  }];
}

let highItems = [];
let mediumItems = [];
let lowItems = [];

for (const item of items) {
  // Safely get properties
  const props = item.json?.properties || 
                item.json || {};

  // Try multiple ways to get each field
  let title = 'No title';
  let company = 'Unknown';
  let category = 'News';
  let importance = 'Low';
  let summary = '';
  let url = '';

  // Title — try different structures
  if (props['Name']?.title?.[0]?.text?.content) {
    title = props['Name'].title[0].text.content;
  } else if (props['title']?.[0]?.text?.content) {
    title = props['title'][0].text.content;
  } else if (item.json?.title) {
    title = item.json.title;
  }

  // Company
  if (props['Company']?.select?.name) {
    company = props['Company'].select.name;
  } else if (item.json?.company) {
    company = item.json.company;
  }

  // Category
  if (props['Category']?.select?.name) {
    category = props['Category'].select.name;
  } else if (item.json?.category) {
    category = item.json.category;
  }

  // Importance
  if (props['Importance']?.select?.name) {
    importance = props['Importance'].select.name;
  } else if (item.json?.importance) {
    importance = item.json.importance;
  }

  // Summary
  if (props['Summary']?.rich_text?.[0]
      ?.text?.content) {
    summary = props['Summary']
              .rich_text[0].text.content;
  } else if (item.json?.summary) {
    summary = item.json.summary;
  }

  // URL
  if (props['Source URL']?.url) {
    url = props['Source URL'].url;
  } else if (item.json?.url) {
    url = item.json.url;
  }

  const entry = `Company: ${company}
Category: ${category}
Headline: ${title}
Analysis: ${summary}
Source: ${url}
---`;

  if (importance === 'High' || 
      importance === '🔴 High') {
    highItems.push(entry);
  } else if (importance === 'Medium' || 
             importance === '🟡 Medium') {
    mediumItems.push(entry);
  } else {
    lowItems.push(entry);
  }
}

let formatted = '';

if (highItems.length > 0) {
  formatted += 'HIGH IMPORTANCE:\n\n';
  formatted += highItems.join('\n') + '\n\n';
}
if (mediumItems.length > 0) {
  formatted += 'MEDIUM IMPORTANCE:\n\n';
  formatted += mediumItems.join('\n') + '\n\n';
}
if (lowItems.length > 0) {
  formatted += 'LOW IMPORTANCE:\n\n';
  formatted += lowItems.join('\n') + '\n\n';
}

if (!formatted) {
  formatted = "Data found but could not parse.";
}

return [{
  json: {
    formattedData: formatted,
    totalItems: items.length,
    highCount: highItems.length,
    mediumCount: mediumItems.length,
    lowCount: lowItems.length
  }
}];

const item = $input.first().json;

const data = (item.formattedData || '')
  .replace(/[\n\r]/g, ' ')
  .replace(/"/g, "'")
  .trim()
  .substring(0, 3000);

const totalItems = item.totalItems || 0;
const highCount = item.highCount || 0;

const prompt = "You are a senior FinTech intelligence analyst. Write a professional weekly executive brief based on this data. Structure it as: 1) WEEK IN REVIEW (2-3 sentences overview) 2) TOP 3 DEVELOPMENTS (most important items with why they matter) 3) MARKET IMPLICATIONS (what this means for FinTech startups) 4) WATCH LIST (what to monitor next week). Keep it under 400 words. Professional tone. Data: " + data;

return [{
  json: {
    cleanPrompt: prompt,
    totalItems: totalItems,
    highCount: highCount
  }
}];

const response = $input.first().json;
const brief = response.choices[0]
              .message.content || '';

const totalItems = $('Build Digest Prompt')
                   .first().json.totalItems;
const highCount = $('Build Digest Prompt')
                  .first().json.highCount;

const today = new Date();
const weekStr = today.toLocaleDateString(
  'en-US', 
  { 
    month: 'long', 
    day: 'numeric', 
    year: 'numeric' 
  }
);

return [{
  json: {
    brief: brief,
    subject: `FinTech Intelligence Brief — Week of ${weekStr}`,
    totalItems: totalItems,
    highCount: highCount,
    weekStr: weekStr
  }
}];
